// Join transcript segments with timestamps so the LLM can cite exact times.
const data = $input.first().json;
const meta = data.metadata || {};
function ts(sec) {
  const s = Math.floor(sec || 0);
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const r = s % 60;
  const mm = (r < 10 ? '0' : '') + r;
  if (h > 0) return h + ':' + (m < 10 ? '0' : '') + m + ':' + mm;
  return m + ':' + mm;
}
const lines = (data.transcript || []).map((seg) => '[' + ts(seg.start) + '] ' + seg.text);
return [
  { json: { videoId: data.video_id, title: meta.title || null, language: data.language || null, transcriptText: lines.join('\n') } },
];

